  POTTERY: 10,
  BOARD_GAMES: 8,
  ESCAPE_ROOM: 8,
  MUSEUM: 7,
  ART_GALLERY: 7,
  CAFE: 6,
  RESTAURANT: 5,
  PARK: 6,
  DESSERT: 5,
  ARCADE: 4,
  BOWLING: 4,
